// Node 2: Input Validation
// Validates transaction_id format and sanitizes input against prompt injection

const body = $input.first().json.body || $input.first().json;

const txnId = body.transaction_id || '';
const motivo = body.motivo || '';

// Validate TXN-XXXXX format
if (!/^TXN-\d{5}$/.test(txnId)) {
  throw new Error(`Invalid transaction_id format: '${txnId}'. Expected TXN-XXXXX.`);
}

// Sanitize against prompt injection (remove known injection patterns)
const INJECTION_PATTERNS = [
  /ignore previous instructions/gi,
  /forget your instructions/gi,
  /you are now/gi,
  /\[SYSTEM\]/gi,
  /\[INST\]/gi,
];

let safetMotivo = motivo;
for (const pattern of INJECTION_PATTERNS) {
  if (pattern.test(safetMotivo)) {
    throw new Error('Potential prompt injection detected in motivo field.');
  }
}

return [{
  json: {
    transaction_id: txnId,
    motivo: safetMotivo.trim().substring(0, 500),
    request_id: `REQ-${Date.now()}`,
    received_at: new Date().toISOString(),
  }
}];

// Node 4: Build ResolveRequest from agent's collected data
// Extracts structured data from agent output and tool call results

const agentOutput = $input.first().json;
const requestId = $('2. Input Validation').first().json.request_id;
const transactionId = $('2. Input Validation').first().json.transaction_id;
const motivo = $('2. Input Validation').first().json.motivo;

// Extract data collected by agent tools
const txData = agentOutput.transaction || agentOutput.tx_data || {};
const policies = agentOutput.policies || [];
const similarCases = agentOutput.similar_cases || [];
const logs = agentOutput.logs || [];
const merchantRisk = agentOutput.merchant_risk || { cb_ratio: 0, flags: [] };
const clientHistory = agentOutput.client_history || { total_chargebacks: 0, flags: [] };
const agentAnalysis = agentOutput.agent_analysis || agentOutput.text || '';

return [{
  json: {
    request_id: requestId,
    resolve_payload: {
      transaction_id: transactionId,
      agent_analysis: agentAnalysis,
      tx_data: txData,
      policies: policies,
      similar_cases: similarCases,
      logs: logs,
      merchant_risk: merchantRisk,
      client_history: clientHistory,
      motivo: motivo,
      cliente_vip: txData.cliente_vip || false,
    }
  }
}];

// Node 8: Auto-Reject (BLOCKER)
// No human review needed — policy is absolute

const resolution = $('5. POST /api/analyze/resolve').first().json;
const judge = $('6. POST /api/analyze/judge').first().json;

return [{
  json: {
    hitl_decision: null,
    final_resolution: resolution,
    judge_evaluation: judge,
    auto_processed: true,
    processing_note: 'Auto-rechazado por BLOCKER de política',
  }
}];

// Node 10: Process HITL Response
// Analyst submitted a decision via the HTML report form

const hitlData = $input.first().json.body || $input.first().json;
const resolution = $('5. POST /api/analyze/resolve').first().json;
const judge = $('6. POST /api/analyze/judge').first().json;

const analystDecision = hitlData.analyst_decision || 'APPROVED';
const analystNotes = hitlData.analyst_notes || '';

// Apply analyst override if provided
let finalResolution = { ...resolution };
if (analystDecision === 'REJECTED') {
  finalResolution.recommended_action = 'REJECT';
  finalResolution.hitl_reason = `Analista rechazó: ${analystNotes}`;
} else if (analystDecision === 'MODIFIED') {
  finalResolution.hitl_reason = `Analista modificó: ${analystNotes}`;
  finalResolution.requires_hitl = false;
} else {
  finalResolution.requires_hitl = false;
}

return [{
  json: {
    hitl_decision: {
      analyst_decision: analystDecision,
      analyst_notes: analystNotes,
      decided_at: new Date().toISOString(),
    },
    final_resolution: finalResolution,
    judge_evaluation: judge,
    auto_processed: false,
  }
}];

// Node 11: Alert (MEDIUM)
// Log alert and auto-process with medium priority

const resolution = $('5. POST /api/analyze/resolve').first().json;
const judge = $('6. POST /api/analyze/judge').first().json;

// In production: send Slack/email notification to team
console.log(`MEDIUM RISK ALERT: ${resolution.transaction_id} — ${resolution.recommended_action}`);

return [{
  json: {
    hitl_decision: null,
    final_resolution: resolution,
    judge_evaluation: judge,
    auto_processed: true,
    processing_note: 'Riesgo MEDIUM — procesado con alerta enviada al equipo',
  }
}];

// Node 12: Auto-Resolve (LOW)
// Low risk — fully automated resolution

const resolution = $('5. POST /api/analyze/resolve').first().json;
const judge = $('6. POST /api/analyze/judge').first().json;

return [{
  json: {
    hitl_decision: null,
    final_resolution: resolution,
    judge_evaluation: judge,
    auto_processed: true,
    processing_note: 'Riesgo LOW — resolución automática',
  }
}];

// Node 18: Error Handler
// Formats error response for webhook

const error = $input.first().json;
console.error('CIRI Agent Error:', JSON.stringify(error, null, 2));

return [{
  json: {
    error: true,
    message: error.message || 'Error interno del sistema',
    workflow: error.workflow?.name || 'Chargeback Agent',
    node: error.node?.name || 'Unknown',
    timestamp: new Date().toISOString(),
  }
}];
